//! Serializable report formats for the results of various commands in the CLAM Shell.

/// The supported formats for the report generated by various commands in the CLAM Shell.
#[derive(clap::ValueEnum, Debug, Clone, Default, Copy, serde::Serialize, serde::Deserialize)]
#[must_use]
#[non_exhaustive]
pub enum ReportFormat {
    /// The json format.
    #[default]
    #[clap(name = "json")]
    Json,
    /// The yaml format.
    #[clap(name = "yaml")]
    Yaml,
}

impl ReportFormat {
    /// The file extension for the report format.
    #[must_use]
    pub const fn file_extension(self) -> &'static str {
        match self {
            Self::Json => "json",
            Self::Yaml => "yaml",
        }
    }

    /// Infers the report format from an extension.
    ///
    /// # Errors
    ///
    /// - If the extension is not recognized as a valid report format.
    pub fn from_extension(ext: &str) -> Result<Self, Box<dyn std::error::Error + Send + Sync>> {
        match ext {
            "json" => Ok(Self::Json),
            "yaml" | "yml" => Ok(Self::Yaml),
            _ => Err(format!("Unsupported file extension for report format: {ext}").into()),
        }
    }

    /// Infers the report format from a file path.
    ///
    /// # Errors
    ///
    /// - If the path does not have an extension.
    /// - If the extension is not recognized as a valid report format.
    pub fn from_path<P: AsRef<std::path::Path>>(path: &P) -> Result<Self, Box<dyn std::error::Error + Send + Sync>> {
        let ext = path
            .as_ref()
            .extension()
            .and_then(|e| e.to_str())
            .ok_or_else(|| format!("Failed to get file extension from path: {:?}", path.as_ref()))?;
        Self::from_extension(ext)
    }

    /// Writes the given report data to the given path in the report format.
    ///
    /// # Errors
    ///
    /// - If there was an error creating the file at the given path.
    /// - If there was an error writing the report data to the file in the specified format.
    pub fn write_report<P: AsRef<std::path::Path>, T: serde::Serialize>(
        self,
        report_data: &T,
        path: &P,
        pretty: bool,
    ) -> Result<(), Box<dyn std::error::Error + Send + Sync>> {
        let file = std::fs::File::create(path)?;
        match self {
            Self::Json => {
                if pretty {
                    serde_json::to_writer_pretty(file, report_data)?;
                } else {
                    serde_json::to_writer(file, report_data)?;
                }
            }
            Self::Yaml => {
                yaml_serde::to_writer(file, report_data)?;
            }
        }
        Ok(())
    }

    /// Reads report data from the given path in the report format.
    ///
    /// # Errors
    ///
    /// - If there was an error opening the file at the given path.
    /// - If there was an error reading the report data from the file in the specified format.
    #[expect(unused)]
    pub fn read_report<P: AsRef<std::path::Path>, T: for<'de> serde::Deserialize<'de>>(path: &P) -> Result<T, Box<dyn std::error::Error + Send + Sync>> {
        let fmt = Self::from_path(path)?;
        let file = std::fs::File::open(path)?;
        let data = match fmt {
            Self::Json => serde_json::from_reader(file)?,
            Self::Yaml => yaml_serde::from_reader(file)?,
        };
        Ok(data)
    }
}
